class Solution {
    public int maxVowels(String s, int k) {
        int maxCount = 0;
        int currentCount = 0;
        int left = 0;
        String vowels = "aeiou";

        for (int right = 0; right < s.length(); right++) {
            if (vowels.indexOf(s.charAt(right)) != -1) {
                currentCount++;
            }

            if (right - left + 1 > k) {
                if (vowels.indexOf(s.charAt(left)) != -1) {
                    currentCount--;
                }
                left++;
            }

            maxCount = Math.max(maxCount, currentCount);
        }

        return maxCount;
    }
}
